// AgentConfigs lists configs, optionally filtered by agent type.
func (r *queryResolver) AgentConfigs(ctx context.Context, agentType *string) ([]model.AgentConfig, error) {
	q := r.Ent.AgentConfig.Query()
	if agentType != nil {
		q = q.Where(agentconfig.AgentType(*agentType))
	}
	// Tenant isolation (LLD-10): browsable content — a caller with a tenant sees
	// their tenant's + platform-global (NULL) configs; admin sees all; malformed
	// tenant fails closed.
	if d := contentScopeFor(ctx); d.apply {
		if d.denyAll {
			q = q.Where(agentconfig.IDEQ(uuid.Nil))
		} else {
			q = q.Where(agentconfig.Or(agentconfig.TenantID(d.tenant), agentconfig.TenantIDIsNil()))
		}
	}
	if env, ok := r.envScopeFor(ctx); ok {
		q = q.Where(agentconfig.Or(agentconfig.EnvironmentID(env), agentconfig.EnvironmentIDIsNil()))
	}
	cs, err := q.Order(orderNewest).All(ctx)
	if err != nil {
		return nil, err
	}
	out := make([]model.AgentConfig, 0, len(cs))
	for _, c := range cs {
		out = append(out, *toModelAgentConfig(c))
	}
	return out, nil
}

// Agents lists agents (admin: all; user: own — owner scope, LLD-01 §4.1).
func (r *queryResolver) Agents(ctx context.Context, filter *model.AgentFilter, pagination *model.Pagination, sort *model.AgentSort) (*model.AgentConnection, error) {
	cu := auth.FromContext(ctx)
	if cu == nil {
		return nil, gqlerror.Errorf("unauthenticated")
	}
	q := r.Ent.Agent.Query()
	// Three-track visibility (LLD-10 §1.3): admin → all; tenant-admin → their
	// whole tenant; regular user → only their own agents (owner track).
	switch {
	case cu.Role == auth.RoleAdmin:
		// no filter
	case cu.Role == auth.RoleTenantAdmin:
		if d := tenantScopeFor(ctx); d.apply {
			if d.denyAll {
				q = q.Where(agent.IDEQ(uuid.Nil))
			} else {
				q = q.Where(agent.TenantID(d.tenant))
			}
		}
	default:
		// Regular user: only their own agents (owner track). Fail CLOSED — a
		// session id that isn't a valid UUID must scope to zero rows, never fall
		// through to an unscoped (all-agents) query.
		if uid, err := uuid.Parse(cu.ID); err == nil {
			q = q.Where(agent.OwnerUserID(uid))
		} else {
			q = q.Where(agent.IDEQ(uuid.Nil))
		}
	}
	if env, ok := r.envScopeFor(ctx); ok { // soft env filter, after tenant (LLD-10 §2.3)
		q = q.Where(agent.Or(agent.EnvironmentID(env), agent.EnvironmentIDIsNil()))
	}

	// Apply the UI filters on top of the visibility scope (前后端整合契约). Cross-
	// entity keywords (owner/key) resolve matching ids first, then constrain by FK.
	if filter != nil {
		if filter.Status != nil {
			q = q.Where(agent.StatusEQ(agent.Status(string(*filter.Status))))
		}
		if v := derefString(filter.Type); v != "" {
			q = q.Where(agent.AgentTypeEQ(v))
		}
		if v := derefString(filter.NameKeyword); v != "" {
			q = q.Where(agent.NameContainsFold(v))
		}
		if v := derefString(filter.OwnerKeyword); v != "" {
			ids, err := r.Ent.User.Query().
				Where(user.Or(user.UsernameContainsFold(v), user.EmailContainsFold(v))).IDs(ctx)
			if err != nil {
				return nil, err
			}
			q = q.Where(agent.OwnerUserIDIn(ids...)) // empty → matches nothing (fail-closed)
		}
		if v := derefString(filter.KeyKeyword); v != "" {
			ids, err := r.Ent.VirtualKey.Query().Where(virtualkey.AliasContainsFold(v)).IDs(ctx)
			if err != nil {
				return nil, err
			}
			q = q.Where(agent.VirtualKeyIDIn(ids...))
		}
	}

	total, err := q.Clone().Count(ctx)
	if err != nil {
		return nil, err
	}

	page, pageSize := 1, 10
	if pagination != nil {
		if pagination.Page > 0 {
			page = pagination.Page
		}
		if pagination.PageSize > 0 {
			pageSize = pagination.PageSize
		}
	}
	as, err := applyAgentSort(q, sort).
		Offset((page - 1) * pageSize).Limit(pageSize).All(ctx)
	if err != nil {
		return nil, err
	}
	// Pre-batch the page's owners + virtual keys into the request cache so the
	// per-row owner/apiKey/credentials field resolvers read from it instead of
	// issuing one User.Get + one VirtualKey.Get per agent (N+1 elimination).
	r.primeAgentRelations(ctx, as)
	nodes := make([]model.Agent, 0, len(as))
	for _, a := range as {
		nodes = append(nodes, *toModelAgent(a))
	}
	totalPages := (total + pageSize - 1) / pageSize
	return &model.AgentConnection{
		Nodes:      nodes,
		TotalCount: total,
		PageInfo:   &model.PageInfo{Page: page, PageSize: pageSize, TotalPages: totalPages},
	}, nil
}

